module t(.v(t$IO));
  inout  t$IO;
  wire t$IO;

  TriState #(.width(32'd1)) t(.I(1'b0), .OE(1'd0), .O(), .IO(t$IO));
endmodule

module TriState
    ( inout IO
    , output O
    , input OE
    , input I
    );
  assign IO = (OE) ? I : { width { 1'bz } };
  assign O  = IO;
endmodule

module linked_io ( .io_A(io), .io_B(io), i, c );
  inout io;
  input i, c;
  assign io = c ? i : 1'bz;
endmodule
